@patch('geo.geocoder.httpx.get')
@patch('geo.geocoder.time.sleep')
def test_reverse_geocode(mock_sleep, mock_get):
    mock_resp = MagicMock()
    mock_resp.json.return_value = {
        'display_name': '1600 Pennsylvania Ave NW, Washington, DC 20500, USA',
        'address': {
            'house_number': '1600',
            'road': 'Pennsylvania Avenue Northwest',
            'city': 'Washington',
            'state': 'District of Columbia',
            'postcode': '20500',
            'country': 'United States'
        }
    }
    mock_get.return_value = mock_resp
    gc = Geocoder()
    addr = gc.reverse_geocode(38.8977, -77.0365)
    assert addr is not None
    assert addr.city == 'Washington'
    assert addr.road == 'Pennsylvania Avenue Northwest'
    assert addr.country == 'United States'


@patch('geo.geocoder.httpx.get')
@patch('geo.geocoder.time.sleep')
def test_reverse_geocode_not_found(mock_sleep, mock_get):
    mock_resp = MagicMock()
    mock_resp.json.return_value = {'error': 'Unable to geocode'}
    mock_get.return_value = mock_resp
    gc = Geocoder()
    addr = gc.reverse_geocode(0.0, 0.0)
    assert addr is None


@patch('geo.geocoder.httpx.get')
@patch('geo.geocoder.time.sleep')
def test_reverse_geocode_uses_town_fallback(mock_sleep, mock_get):
    mock_resp = MagicMock()
    mock_resp.json.return_value = {
        'display_name': 'Rural Town, State, Country',
        'address': {
            'town': 'Rural Town',
            'state': 'State',
            'country': 'Country'
        }
    }
    mock_get.return_value = mock_resp
    gc = Geocoder()
    addr = gc.reverse_geocode(35.0, -80.0)
    assert addr.city == 'Rural Town'  # Falls back to 'town' when 'city' absent
